#!/usr/bin/env python3
"""
Pre-commit Hook Generator

Generates a pre-commit hook that runs AI code review on staged files.
"""

import os
import sys
from pathlib import Path


HOOK_TEMPLATE = '''#!/bin/bash
# AI Code Review - Pre-commit Hook
# Auto-generated by generate-pre-commit-hook.py

set -e

echo "🔍 Running AI Code Review on staged files..."

# Get list of staged Python, JavaScript, and other supported files
STAGED_FILES=$(git diff --cached --name-only --diff-filter=ACM | grep -E '\\.(py|js|jsx|ts|tsx|java|go|rs)$' || true)

if [ -z "$STAGED_FILES" ]; then
    echo "✅ No code files to review"
    exit 0
fi

# Save staged files to temp directory for analysis
TEMP_DIR=$(mktemp -d)
trap "rm -rf $TEMP_DIR" EXIT

for FILE in $STAGED_FILES; do
    mkdir -p "$TEMP_DIR/$(dirname $FILE)"
    git show ":$FILE" > "$TEMP_DIR/$FILE"
done

# Run analysis on staged files
python3 cli.py analyze \\
    --path "$TEMP_DIR" \\
    --severity-threshold {severity_threshold} \\
    --max-issues {max_issues} \\
    --output-format text \\
    --exit-on-threshold

EXIT_CODE=$?

if [ $EXIT_CODE -ne 0 ]; then
    echo ""
    echo "❌ Code review found issues. Commit blocked."
    echo "   Fix the issues or use 'git commit --no-verify' to skip this check."
    exit 1
fi

echo "✅ Code review passed!"
exit 0
'''


def generate_hook(
    severity_threshold: str = 'error',
    max_issues: int = 5,
    output_path: str = None
):
    """
    Generate pre-commit hook

    Args:
        severity_threshold: Minimum severity to block commit
        max_issues: Maximum number of issues before blocking
        output_path: Path to write hook (defaults to .git/hooks/pre-commit)
    """
    # Generate hook content
    hook_content = HOOK_TEMPLATE.format(
        severity_threshold=severity_threshold,
        max_issues=max_issues
    )

    # Determine output path
    if not output_path:
        # Try to find .git directory
        current_dir = Path.cwd()
        git_dir = current_dir / '.git'

        if not git_dir.exists():
            # Try parent directories
            for parent in current_dir.parents:
                git_dir = parent / '.git'
                if git_dir.exists():
                    break
            else:
                print("❌ Error: Could not find .git directory")
                print("   Run this command from within a git repository")
                return False

        output_path = git_dir / 'hooks' / 'pre-commit'
    else:
        output_path = Path(output_path)

    # Create hooks directory if it doesn't exist
    output_path.parent.mkdir(parents=True, exist_ok=True)

    # Write hook file
    output_path.write_text(hook_content)

    # Make executable
    os.chmod(output_path, 0o755)

    print(f"✅ Pre-commit hook generated: {output_path}")
    print(f"   Severity threshold: {severity_threshold}")
    print(f"   Max issues: {max_issues}")
    print("")
    print("ℹ️  The hook will run on every commit.")
    print("   To skip the hook, use: git commit --no-verify")

    return True


def main():
    """Main entry point"""
    import argparse

    parser = argparse.ArgumentParser(
        description='Generate AI Code Review pre-commit hook'
    )
    parser.add_argument(
        '--severity-threshold',
        choices=['info', 'warning', 'error', 'critical'],
        default='error',
        help='Minimum severity to block commit (default: error)'
    )
    parser.add_argument(
        '--max-issues',
        type=int,
        default=5,
        help='Maximum issues before blocking commit (default: 5)'
    )
    parser.add_argument(
        '--output',
        help='Output path (default: .git/hooks/pre-commit)'
    )

    args = parser.parse_args()

    success = generate_hook(
        severity_threshold=args.severity_threshold,
        max_issues=args.max_issues,
        output_path=args.output
    )

    return 0 if success else 1


if __name__ == '__main__':
    sys.exit(main())
